if let Some(ref verifier) = self.verifier {
    if let Err(e) = verifier.verify_block(block.sealed_block()) {
        ritual_metrics::block::log_block_verify_failure(
            &block.hash(),
            block.number(),
            &e,
        );
        tracing::error!(
            target: "ritual::block_verification",
            block_hash = %block.hash(),
            block_number = block.number(),
            error = ?e,
            "Block verification failed"
        );
        return Err(BlockExecutionError::msg(format!(
            "Block verification failed: {:?}",
            e
        )));
    }
}

